{
  "openApiSpec": {
    "openapi": "3.0.0",
    "info": {
      "title": "Hello World Function Generator API",
      "version": "1.0.0",
      "description": "API for generating, saving, and managing Hello World functions in multiple programming languages"
    },
    "servers": [
      {"url": "/api/v1"}
    ],
    "paths": {
      "/auth/register": {
        "post": {
          "summary": "Register a new user account",
          "tags": ["Authentication"],
          "requestBody": {
            "required": true,
            "content": {
              "application/json": {
                "schema": {
                  "type": "object",
                  "required": ["email", "password"],
                  "properties": {
                    "email": {"type": "string", "format": "email"},
                    "password": {"type": "string", "minLength": 8, "pattern": "^(?=.*[0-9])(?=.*[!@#$%^&*]).*$"}
                  }
                }
              }
            }
          },
          "responses": {
            "201": {
              "description": "Account created successfully",
              "content": {
                "application/json": {
                  "schema": {"$ref": "#/components/schemas/AuthResponse"}
                }
              }
            },
            "400": {"$ref": "#/components/responses/BadRequest"},
            "409": {"description": "Email already registered"}
          }
        }
      },
      "/auth/login": {
        "post": {
          "summary": "Login with email and password",
          "tags": ["Authentication"],
          "requestBody": {
            "required": true,
            "content": {
              "application/json": {
                "schema": {
                  "type": "object",
                  "required": ["email", "password"],
                  "properties": {
                    "email": {"type": "string", "format": "email"},
                    "password": {"type": "string"},
                    "rememberMe": {"type": "boolean", "default": false}
                  }
                }
              }
            }
          },
          "responses": {
            "200": {
              "description": "Login successful",
              "content": {
                "application/json": {
                  "schema": {"$ref": "#/components/schemas/AuthResponse"}
                }
              }
            },
            "401": {"$ref": "#/components/responses/Unauthorized"},
            "403": {"description": "Email not verified"}
          }
        }
      },
      "/auth/logout": {
        "post": {
          "summary": "Logout current user",
          "tags": ["Authentication"],
          "security": [{"bearerAuth": []}],
          "responses": {
            "204": {"description": "Logout successful"},
            "401": {"$ref": "#/components/responses/Unauthorized"}
          }
        }
      },
      "/auth/verify-email": {
        "post": {
          "summary": "Verify email address with token",
          "tags": ["Authentication"],
          "requestBody": {
            "required": true,
            "content": {
              "application/json": {
                "schema": {
                  "type": "object",
                  "required": ["token"],
                  "properties": {
                    "token": {"type": "string"}
                  }
                }
              }
            }
          },
          "responses": {
            "200": {"description": "Email verified successfully"},
            "400": {"description": "Invalid or expired token"}
          }
        }
      },
      "/auth/resend-verification": {
        "post": {
          "summary": "Resend verification email",
          "tags": ["Authentication"],
          "requestBody": {
            "required": true,
            "content": {
              "application/json": {
                "schema": {
                  "type": "object",
                  "required": ["email"],
                  "properties": {
                    "email": {"type": "string", "format": "email"}
                  }
                }
              }
            }
          },
          "responses": {
            "200": {"description": "Verification email sent"},
            "404": {"description": "User not found"}
          }
        }
      },
      "/auth/forgot-password": {
        "post": {
          "summary": "Request password reset",
          "tags": ["Authentication"],
          "requestBody": {
            "required": true,
            "content": {
              "application/json": {
                "schema": {
                  "type": "object",
                  "required": ["email"],
                  "properties": {
                    "email": {"type": "string", "format": "email"}
                  }
                }
              }
            }
          },
          "responses": {
            "200": {"description": "Password reset email sent"},
            "404": {"description": "User not found"}
          }
        }
      },
      "/auth/reset-password": {
        "post": {
          "summary": "Reset password with token",
          "tags": ["Authentication"],
          "requestBody": {
            "required": true,
            "content": {
              "application/json": {
                "schema": {
                  "type": "object",
                  "required": ["token", "password"],
                  "properties": {
                    "token": {"type": "string"},
                    "password": {"type": "string", "minLength": 8}
                  }
                }
              }
            }
          },
          "responses": {
            "200": {"description": "Password reset successful"},
            "400": {"description": "Invalid or expired token"}
          }
        }
      },
      "/auth/refresh": {
        "post": {
          "summary": "Refresh authentication token",
          "tags": ["Authentication"],
          "requestBody": {
            "required": true,
            "content": {
              "application/json": {
                "schema": {
                  "type": "object",
                  "required": ["refreshToken"],
                  "properties": {
                    "refreshToken": {"type": "string"}
                  }
                }
              }
            }
          },
          "responses": {
            "200": {
              "description": "Token refreshed",
              "content": {
                "application/json": {
                  "schema": {"$ref": "#/components/schemas/AuthResponse"}
                }
              }
            },
            "401": {"description": "Invalid refresh token"}
          }
        }
      },
      "/languages": {
        "get": {
          "summary": "Get list of supported programming languages",
          "tags": ["Languages"],
          "parameters": [
            {
              "name": "search",
              "in": "query",
              "schema": {"type": "string"},
              "description": "Filter languages by name"
            },
            {
              "name": "category",
              "in": "query",
              "schema": {"type": "string", "enum": ["popular", "web", "mobile", "system", "functional", "all"]},
              "description": "Filter by language category"
            }
          ],
          "responses": {
            "200": {
              "description": "List of supported languages",
              "content": {
                "application/json": {
                  "schema": {
                    "type": "array",
                    "items": {"$ref": "#/components/schemas/Language"}
                  }
                }
              }
            }
          }
        }
      },
      "/generate": {
        "post": {
          "summary": "Generate Hello World function",
          "tags": ["Code Generation"],
          "requestBody": {
            "required": true,
            "content": {
              "application/json": {
                "schema": {"$ref": "#/components/schemas/GenerateRequest"}
              }
            }
          },
          "responses": {
            "200": {
              "description": "Function generated successfully",
              "content": {
                "application/json": {
                  "schema": {"$ref": "#/components/schemas/GeneratedFunction"}
                }
              }
            },
            "400": {"$ref": "#/components/responses/BadRequest"},
            "422": {"description": "Invalid generation parameters"}
          }
        }
      },
      "/functions": {
        "get": {
          "summary": "Get user's saved functions",
          "tags": ["User Functions"],
          "security": [{"bearerAuth": []}],
          "parameters": [
            {
              "name": "page",
              "in": "query",
              "schema": {"type": "integer", "minimum": 1, "default": 1},
              "description": "Page number"
            },
            {
              "name": "limit",
              "in": "query",
              "schema": {"type": "integer", "minimum": 1, "maximum": 100, "default": 20},
              "description": "Items per page"
            },
            {
              "name": "search",
              "in": "query",
              "schema": {"type": "string"},
              "description": "Search in function names and content"
            },
            {
              "name": "language",
              "in": "query",
              "schema": {"type": "string"},
              "description": "Filter by programming language"
            },
            {
              "name": "sortBy",
              "in": "query",
              "schema": {"type": "string", "enum": ["name", "language", "createdAt", "updatedAt"], "default": "createdAt"},
              "description": "Sort field"
            },
            {
              "name": "sortOrder",
              "in": "query",
              "schema": {"type": "string", "enum": ["asc", "desc"], "default": "desc"},
              "description": "Sort order"
            }
          ],
          "responses": {
            "200": {
              "description": "User's saved functions",
              "content": {
                "application/json": {
                  "schema": {"$ref": "#/components/schemas/PaginatedFunctions"}
                }
              }
            },
            "401": {"$ref": "#/components/responses/Unauthorized"}
          }
        },
        "post": {
          "summary": "Save a generated function",
          "tags": ["User Functions"],
          "security": [{"bearerAuth": []}],
          "requestBody": {
            "required": true,
            "content": {
              "application/json": {
                "schema": {"$ref": "#/components/schemas/SaveFunctionRequest"}
              }
            }
          },
          "responses": {
            "201": {
              "description": "Function saved successfully",
              "content": {
                "application/json": {
                  "schema": {"$ref": "#/components/schemas/SavedFunction"}
                }
              }
            },
            "400": {"$ref": "#/components/responses/BadRequest"},
            "401": {"$ref": "#/components/responses/Unauthorized"},
            "409": {"description": "Function name already exists"}
          }
        }
      },
      "/functions/{id}": {
        "get": {
          "summary": "Get a specific saved function",
          "tags": ["User Functions"],
          "security": [{"bearerAuth": []}],
          "parameters": [
            {
              "name": "id",
              "in": "path",
              "required": true,
              "schema": {"type": "string", "format": "uuid"}
            }
          ],
          "responses": {
            "200": {
              "description": "Saved function details",
              "content": {
                "application/json": {
                  "schema": {"$ref": "#/components/schemas/SavedFunction"}
                }
              }
            },
            "401": {"$ref": "#/components/responses/Unauthorized"},
            "404": {"$ref": "#/components/responses/NotFound"}
          }
        },
        "put": {
          "summary": "Update a saved function",
          "tags": ["User Functions"],
          "security": [{"bearerAuth": []}],
          "parameters": [
            {
              "name": "id",
              "in": "path",
              "required": true,
              "schema": {"type": "string", "format": "uuid"}
            }
          ],
          "requestBody": {
            "required": true,
            "content": {
              "application/json": {
                "schema": {"$ref": "#/components/schemas/UpdateFunctionRequest"}
              }
            }
          },
          "responses": {
            "200": {
              "description": "Function updated successfully",
              "content": {
                "application/json": {
                  "schema": {"$ref": "#/components/schemas/SavedFunction"}
                }
              }
            },
            "400": {"$ref": "#/components/responses/BadRequest"},
            "401": {"$ref": "#/components/responses/Unauthorized"},
            "404": {"$ref": "#/components/responses/NotFound"}
          }
        },
        "delete": {
          "summary": "Delete a saved function",
          "tags": ["User Functions"],
          "security": [{"bearerAuth": []}],
          "parameters": [
            {
              "name": "id",
              "in": "path",
              "required": true,
              "schema": {"type": "string", "format": "uuid"}
            }
          ],
          "responses": {
            "204": {"description": "Function deleted successfully"},
            "401": {"$ref": "#/components/responses/Unauthorized"},
            "404": {"$ref": "#/components/responses/NotFound"}
          }
        }
      },
      "/functions/bulk-delete": {
        "post": {
          "summary": "Delete multiple saved functions",
          "tags": ["User Functions"],
          "security": [{"bearerAuth": []}],
          "requestBody": {
            "required": true,
            "content": {
              "application/json": {
                "schema": {
                  "type": "object",
                  "required": ["functionIds"],
                  "properties": {
                    "functionIds": {
                      "type": "array",
                      "items": {"type": "string", "format": "uuid"},
                      "minItems": 1,
                      "maxItems": 50
                    }
                  }
                }
              }
            }
          },
          "responses": {
            "200": {
              "description": "Functions deleted successfully",
              "content": {
                "application/json": {
                  "schema": {
                    "type": "object",
                    "properties": {
                      "deleted": {"type": "integer"},
                      "failed": {"type": "array", "items": {"type": "string"}}
                    }
                  }
                }
              }
            },
            "401": {"$ref": "#/components/responses/Unauthorized"}
          }
        }
      },
      "/export": {
        "post": {
          "summary": "Export function to file",
          "tags": ["Export"],
          "requestBody": {
            "required": true,
            "content": {
              "application/json": {
                "schema": {"$ref": "#/components/schemas/ExportRequest"}
              }
            }
          },
          "responses": {
            "200": {
              "description": "File exported successfully",
              "content": {
                "application/octet-stream": {
                  "schema": {"type": "string", "format": "binary"}
                }
              },
              "headers": {
                "Content-Disposition": {
                  "schema": {"type": "string"},
                  "description": "attachment; filename=..."
                }
              }
            },
            "400": {"$ref": "#/components/responses/BadRequest"}
          }
        }
      },
      "/export/bulk": {
        "post": {
          "summary": "Export multiple functions as ZIP",
          "tags": ["Export"],
          "security": [{"bearerAuth": []}],
          "requestBody": {
            "required": true,
            "content": {
              "application/json": {
                "schema": {
                  "type": "object",
                  "required": ["functionIds"],
                  "properties": {
                    "functionIds": {
                      "type": "array",
                      "items": {"type": "string", "format": "uuid"},
                      "minItems": 1,
                      "maxItems": 50
                    }
                  }
                }
              }
            }
          },
          "responses": {
            "200": {
              "description": "ZIP file with functions",
              "content": {
                "application/zip": {
                  "schema": {"type": "string", "format": "binary"}
                }
              }
            },
            "401": {"$ref": "#/components/responses/Unauthorized"}
          }
        }
      },
      "/share": {
        "post": {
          "summary": "Create shareable URL for function",
          "tags": ["Sharing"],
          "requestBody": {
            "required": true,
            "content": {
              "application/json": {
                "schema": {"$ref": "#/components/schemas/ShareRequest"}
              }
            }
          },
          "responses": {
            "201": {
              "description": "Share URL created",
              "content": {
                "application/json": {
                  "schema": {"$ref": "#/components/schemas/ShareResponse"}
                }
              }
            },
            "400": {"$ref": "#/components/responses/BadRequest"}
          }
        }
      },
      "/share/{shareId}": {
        "get": {
          "summary": "Get shared function",
          "tags": ["Sharing"],
          "parameters": [
            {
              "name": "shareId",
              "in": "path",
              "required": true,
              "schema": {"type": "string"}
            }
          ],
          "responses": {
            "200": {
              "description": "Shared function details",
              "content": {
                "application/json": {
                  "schema": {"$ref": "#/components/schemas/SharedFunction"}
                }
              }
            },
            "404": {"$ref": "#/components/responses/NotFound"},
            "410": {"description": "Shared function expired"}
          }
        }
      },
      "/templates": {
        "get": {
          "summary": "Get function templates",
          "tags": ["Templates"],
          "parameters": [
            {
              "name": "language",
              "in": "query",
              "schema": {"type": "string"},
              "description": "Filter by programming language"
            },
            {
              "name": "difficulty",
              "in": "query",
              "schema": {"type": "string", "enum": ["beginner", "intermediate", "advanced"]},
              "description": "Filter by difficulty level"
            },
            {
              "name": "category",
              "in": "query",
              "schema": {"type": "string", "enum": ["basic", "with-parameters", "oop", "functional"]},
              "description": "Filter by template category"
            }
          ],
          "responses": {
            "200": {
              "description": "List of function templates",
              "content": {
                "application/json": {
                  "schema": {
                    "type": "array",
                    "items": {"$ref": "#/components/schemas/FunctionTemplate"}
                  }
                }
              }
            }
          }
        }
      },
      "/templates/{id}": {
        "get": {
          "summary": "Get specific template",
          "tags": ["Templates"],
          "parameters": [
            {
              "name": "id",
              "in": "path",
              "required": true,
              "schema": {"type": "string"}
            }
          ],
          "responses": {
            "200": {
              "description": "Template details",
              "content": {
                "application/json": {
                  "schema": {"$ref": "#/components/schemas/FunctionTemplate"}
                }
              }
            },
            "404": {"$ref": "#/components/responses/NotFound"}
          }
        }
      },
      "/user/profile": {
        "get": {
          "summary": "Get user profile",
          "tags": ["User"],
          "security": [{"bearerAuth": []}],
          "responses": {
            "200": {
              "description": "User profile",
              "content": {
                "application/json": {
                  "schema": {"$ref": "#/components/schemas/UserProfile"}
                }
              }
            },
            "401": {"$ref": "#/components/responses/Unauthorized"}
          }
        },
        "put": {
          "summary": "Update user profile",
          "tags": ["User"],
          "security": [{"bearerAuth": []}],
          "requestBody": {
            "required": true,
            "content": {
              "application/json": {
                "schema": {
                  "type": "object",
                  "properties": {
                    "firstName": {"type": "string", "maxLength": 50},
                    "lastName": {"type": "string", "maxLength": 50},
                    "preferences": {"$ref": "#/components/schemas/UserPreferences"}
                  }
                }
              }
            }
          },
          "responses": {
            "200": {
              "description": "Profile updated",
              "content": {
                "application/json": {
                  "schema": {"$ref": "#/components/schemas/UserProfile"}
                }
              }
            },
            "401": {"$ref": "#/components/responses/Unauthorized"}
          }
        }
      },
      "/user/statistics": {
        "get": {
          "summary": "Get user usage statistics",
          "tags": ["User"],
          "security": [{"bearerAuth": []}],
          "parameters": [
            {
              "name": "period",
              "in": "query",
              "schema": {"type": "string", "enum": ["7d", "30d", "90d", "1y", "all"], "default": "30d"},
              "description": "Statistics period"
            }
          ],
          "responses": {
            "200": {
              "description": "User statistics",
              "content": {
                "application/json": {
                  "schema": {"$ref": "#/components/schemas/UserStatistics"}
                }
              }
            },
            "401": {"$ref": "#/components/responses/Unauthorized"}
          }
        }
      },
      "/health": {
        "get": {
          "summary": "Health check endpoint",
          "tags": ["System"],
          "responses": {
            "200": {
              "description": "Service is healthy",
              "content": {
                "application/json": {
                  "schema": {
                    "type": "object",
                    "properties": {
                      "status": {"type": "string", "example": "healthy"},
                      "timestamp": {"type": "string", "format": "date-time"},
                      "version": {"type": "string", "example": "1.0.0"}
                    }
                  }
                }
              }
            }
          }
        }
      }
    },
    "components": {
      "schemas": {
        "AuthResponse": {
          "type": "object",
          "properties": {
            "user": {"$ref": "#/components/schemas/User"},
            "accessToken": {"type": "string"},
            "refreshToken": {"type": "string"},
            "expiresIn": {"type": "integer", "description": "Token expiry in seconds"}
          }
        },
        "User": {
          "type": "object",
          "properties": {
            "id": {"type": "string", "format": "uuid"},
            "email": {"type": "string", "format": "email"},
            "firstName": {"type": "string"},
            "lastName": {"type": "string"},
            "emailVerified": {"type": "boolean"},
            "createdAt": {"type": "string", "format": "date-time"},
            "lastLoginAt": {"type": "string", "format": "date-time"}
          }
        },
        "Language": {
          "type": "object",
          "properties": {
            "id": {"type": "string"},
            "name": {"type": "string"},
            "displayName": {"type": "string"},
            "extension": {"type": "string"},
            "category": {"type": "string"},
            "icon": {"type": "string"},
            "popularity": {"type": "integer"},
            "syntaxHighlighting": {"type": "string"}
          }
        },
        "GenerateRequest": {
          "type": "object",
          "required": ["language"],
          "properties": {
            "language": {"type": "string"},
            "templateId": {"type": "string"},
            "customizations": {
              "type": "object",
              "properties": {
                "functionName": {"type": "string", "default": "helloWorld"},
                "message": {"type": "string", "default": "Hello, World!"},
                "outputType": {"type": "string", "enum": ["console", "return", "print"], "default": "console"},
                "includeComments": {"type": "boolean", "default": true},
                "parameters": {
                  "type": "array",
                  "items": {
                    "type": "object",
                    "properties": {
                      "name": {"type": "string"},
                      "type": {"type": "string"},
                      "defaultValue": {"type": "string"}
                    }
                  }
                }
              }
            }
          }
        },
        "GeneratedFunction": {
          "type": "object",
          "properties": {
            "id": {"type": "string"},
            "language": {"type": "string"},
            "code": {"type": "string"},
            "highlightedCode": {"type": "string"},
            "filename": {"type": "string"},
            "metadata": {
              "type": "object",
              "properties": {
                "functionName": {"type": "string"},
                "parameters": {"type": "array", "items": {"type": "string"}},
                "outputType": {"type": "string"},
                "linesOfCode": {"type": "integer"}
              }
            },
            "generatedAt": {"type": "string", "format": "date-time"}
          }
        },
        "SaveFunctionRequest": {
          "type": "object",
          "required": ["name", "language", "code"],
          "properties": {
            "name": {"type": "string", "minLength": 1, "maxLength": 100},
            "description": {"type": "string", "maxLength": 500},
            "language": {"type": "string"},
            "code": {"type": "string"},
            "customizations": {"type": "object"},
            "tags": {"type": "array", "items": {"type": "string"}, "maxItems": 10}
          }
        },
        "SavedFunction": {
          "type": "object",
          "properties": {
            "id": {"type": "string", "format": "uuid"},
            "userId": {"type": "string", "format": "uuid"},
            "name": {"type": "string"},
            "description": {"type": "string"},
            "language": {"type": "string"},
            "code": {"type": "string"},
            "customizations": {"type": "object"},
            "tags": {"type": "array", "items": {"type": "string"}},
            "createdAt": {"type": "string", "format": "date-time"},
            "updatedAt": {"type": "string", "format": "date-time"}
          }
        },
        "UpdateFunctionRequest": {
          "type": "object",
          "properties": {
            "name": {"type": "string", "minLength": 1, "maxLength": 100},
            "description": {"type": "string", "maxLength": 500},
            "code": {"type": "string"},
            "tags": {"type": "array", "items": {"type": "string"}, "maxItems": 10}
          }
        },
        "PaginatedFunctions": {
          "type": "object",
          "properties": {
            "functions": {"type": "array", "items": {"$ref": "#/components/schemas/SavedFunction"}},
            "pagination": {
              "type": "object",
              "properties": {
                "page": {"type": "integer"},
                "limit": {"type": "integer"},
                "total": {"type": "integer"},
                "pages": {"type": "integer"},
                "hasNext": {"type": "boolean"},
                "hasPrev": {"type": "boolean"}
              }
            }
          }
        },
        "ExportRequest": {
          "type": "object",
          "required": ["code", "language"],
          "properties": {
            "code": {"type": "string"},
            "language": {"type": "string"},
            "filename": {"type": "string"},
            "format": {"type": "string", "enum": ["source", "text"], "default": "source"},
